INSERT OR REPLACE INTO courses (id, operator_id, slug, title, summary, cover_color, emoji, primary_lang, status, est_minutes) VALUES ('c_coronet_peak_2026', 'op_nzski', 'coronet-peak-2026', 'Coronet Peak 2026', 'Queenstown''s pioneer ski field — terrain, lessons, snowmaking and the 2026 capital programme. Pitch with confidence to all guest types.', 'linear-gradient(135deg,#0e3d4a 0%, #134e5e 50%, #1a6679 100%)', '⛷️', 'en', 'published', 25);
INSERT OR REPLACE INTO modules (id, course_id, slug, title, summary, est_minutes, position) VALUES ('m_cp_overview', 'c_coronet_peak_2026', 'mountain-overview', 'Mountain overview', 'Where Coronet Peak sits, who it suits, the headline 2026 changes.', 5, 1);
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_overview_000', 'm_cp_overview', 0, 'text', '**Coronet Peak** is NZSki''s pioneer ski field — 25 minutes from Queenstown CBD, suited to all abilities with a strong intermediate and family draw. Open daily winter 2026 from **June 13** through to **early October**.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_overview_001', 'm_cp_overview', 1, 'callout', '**New for 2026** — A South Island–first **Snow Factory** producing premium snow regardless of temperature, dramatically improving the early-season experience.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_overview_002', 'm_cp_overview', 2, 'text', 'Headline 2026 capital programme: Kidzone carpet upgrade, new Snow Factory, **new Snowsports Heli Premium Private** experience launched alongside existing private-coaching tiers.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO modules (id, course_id, slug, title, summary, est_minutes, position) VALUES ('m_cp_lifts_terrain', 'c_coronet_peak_2026', 'lifts-terrain', 'Lifts & terrain map', 'Lift configuration, terrain mix, what to recommend for beginners vs advanced.', 8, 2);
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_lifts_terrain_000', 'm_cp_lifts_terrain', 0, 'text', 'Lift network across Coronet''s bowl plus the M1 Express on the back face. Beginner zone fed by Meadows and Kidzone carpets; intermediates spread across Greengates / Rocky Gully; experts head to Back Bowls when conditions allow.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_lifts_terrain_001', 'm_cp_lifts_terrain', 1, 'image', NULL, NULL, NULL, NULL, 'Coronet Peak base lodge — winter 2026', 'en');
INSERT OR REPLACE INTO modules (id, course_id, slug, title, summary, est_minutes, position) VALUES ('m_cp_lessons', 'c_coronet_peak_2026', 'lessons-coaching', 'Lessons & coaching', 'Three private-coaching tiers — Premium, Performance, Premium Heli. Who they''re for and how to position them.', 6, 3);
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_lessons_000', 'm_cp_lessons', 0, 'text', 'Coronet Peak offers **three tiers of private coaching**, each capped at 4 guests per instructor. Choosing the right tier depends on ability level and what the guest wants to get out of the day.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_lessons_001', 'm_cp_lessons', 1, 'callout', '**Premium Privates** — family-friendly, all abilities. **NZ$ from 1,099/day**. Recommend for first-timers through to confident intermediates and mixed-ability groups.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_lessons_002', 'm_cp_lessons', 2, 'callout', '**Performance Privates** — technique-focused for advanced skiers/snowboarders. **NZ$ from 1,299/day**. Recommend when the guest''s goal is measurable improvement.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_lessons_003', 'm_cp_lessons', 3, 'callout', '**Premium Heli Privates** — backcountry heli access for advanced+ guests. **NZ$ from 2,890/day** including 2 drop-offs and full mountain-safety briefing. Subject to weather. Only available at Coronet Peak (not Remarkables or Mt Hutt).', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_lessons_004', 'm_cp_lessons', 4, 'video', NULL, NULL, 'STREAM_UID_CORONET_AERIAL', NULL, 'Coronet Peak — Aerial 2026 (12:34)', 'en');
INSERT OR REPLACE INTO modules (id, course_id, slug, title, summary, est_minutes, position) VALUES ('m_cp_pricing', 'c_coronet_peak_2026', 'pricing-inclusions', 'Pricing & inclusions', 'Lift passes, rentals, bundles, and trade rates.', 6, 4);
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_pricing_000', 'm_cp_pricing', 0, 'text', 'Day lift passes start at **NZ$ 169 adult / 99 child** at gate; **advance purchase** discounts available 14+ days out. 3-mountain pass (Coronet + Remarkables + Mt Hutt) is the best value for guests staying 4+ days in NZ.', NULL, NULL, NULL, NULL, 'en');
INSERT OR REPLACE INTO modules (id, course_id, slug, title, summary, est_minutes, position) VALUES ('m_cp_booking', 'c_coronet_peak_2026', 'booking-faq', 'Booking & FAQ', 'How agents book, snow-day policy, transport from Queenstown.', 7, 5);
INSERT OR REPLACE INTO content_blocks (id, module_id, position, kind, text_md, image_r2_key, video_uid, pdf_r2_key, caption, lang) VALUES ('b_m_cp_booking_000', 'm_cp_booking', 0, 'text', 'Trade bookings via the NZSki Travel Trade portal. **Snow-day cancellation policy:** if the resort closes for the full day, lift-pass holders receive a credit (not refund) usable within 24 months at any NZSki resort. Lessons and heli are rebooked subject to availability or fully refunded.', NULL, NULL, NULL, NULL, 'en');

